const TOPIC = 'qw/nr';
const MFRR_SOURCES = ['fusebox', 'kratt'];
const MQTT_LOST_FAILSAFE_MS = 5 * 60 * 1000;
const MAX_DURATION_MS = 30 * 60 * 1000;
const DESS_OFF_DELAY_MS = 2000;

let sm = flow.get('qw_sm') || {
    state: 'IDLE', event_start_ts: null, last_signed_watts: 0,
    mqtt_lost_at: null, pending_token: null
};

const qw_source = flow.get('qw_source') || '';
const qw_mode = flow.get('qw_mode') || '';
const qw_powerlimit = parseInt(flow.get('qw_powerlimit'), 10) || 0;
const qw_connected = !!flow.get('qw_connected');
const now = Date.now();

const isMfrr = MFRR_SOURCES.indexOf(qw_source) >= 0;
const signedWatts = (qw_mode === 'frrup' ? -Math.abs(qw_powerlimit) : Math.abs(qw_powerlimit));

// Shared flag for a co-resident curtailment flow (see curtailment-mfrr-aware.md).
function setMfrr(active, mode, watts) {
    global.set('qw_mfrr', { active: active, mode: mode || '', signed_watts: watts || 0, ts: now });
}

function publishState(extra) {
    return { topic: TOPIC + '/state', retain: true, payload: Object.assign({
        state: sm.state, qw_source: qw_source, qw_mode: qw_mode,
        qw_powerlimit: qw_powerlimit, qw_connected: qw_connected,
        signed_watts: sm.last_signed_watts,
        event_start_ts: sm.event_start_ts ? new Date(sm.event_start_ts).toISOString() : null,
        timestamp: new Date(now).toISOString()
    }, extra || {}) };
}
function publishError(error, context) {
    return { topic: TOPIC + '/error', payload: { error: error, context: context || {}, timestamp: new Date(now).toISOString() } };
}
function execDess(arg) { return { payload: arg }; }
function execSp(watts) { return { payload: String(watts) }; }
function setStatus(text, fill) {
    node.status({ fill: fill || (sm.state === 'ACTIVE' ? 'yellow' : 'green'), shape: 'dot', text: text });
}

// === Failsafe checks (only when ACTIVE) ===
if (sm.state === 'ACTIVE') {
    if (!qw_connected) {
        if (sm.mqtt_lost_at === null) sm.mqtt_lost_at = now;
        if (now - sm.mqtt_lost_at > MQTT_LOST_FAILSAFE_MS) {
            sm = { state: 'IDLE', event_start_ts: null, last_signed_watts: 0, mqtt_lost_at: null, pending_token: null };
            flow.set('qw_sm', sm); setMfrr(false);
            setStatus('FAILSAFE mqtt_lost', 'red');
            return [execDess('on'), execSp(0), [publishState({ failsafe: 'mqtt_lost_5min' }), publishError('mqtt_lost_5min', { qw_source })]];
        }
    } else { sm.mqtt_lost_at = null; }

    if (sm.event_start_ts && (now - sm.event_start_ts > MAX_DURATION_MS)) {
        const duration_ms = now - sm.event_start_ts;
        sm = { state: 'IDLE', event_start_ts: null, last_signed_watts: 0, mqtt_lost_at: null, pending_token: null };
        flow.set('qw_sm', sm); setMfrr(false);
        setStatus('FAILSAFE 30min', 'red');
        return [execDess('on'), execSp(0), [publishState({ failsafe: 'max_duration_30min', duration_ms }), publishError('mfrr_event_exceeded_30min', { qw_source, duration_ms })]];
    }
}

// === Normal transitions ===
if (sm.state === 'IDLE' && isMfrr) {
    const token = 'evt-' + now;
    sm.state = 'ACTIVE'; sm.event_start_ts = now; sm.last_signed_watts = signedWatts; sm.pending_token = token;
    flow.set('qw_sm', sm); setMfrr(true, qw_mode, signedWatts);
    setStatus('ACTIVE ' + signedWatts + ' W (starting)', 'yellow');
    setTimeout(function () {
        const cur = flow.get('qw_sm');
        if (!cur || cur.state !== 'ACTIVE' || cur.pending_token !== token) return;
        cur.pending_token = null; flow.set('qw_sm', cur);
        node.send([null, execSp(cur.last_signed_watts), publishState({ phase: 'setpoint_applied' })]);
    }, DESS_OFF_DELAY_MS);
    return [execDess('off'), null, publishState({ phase: 'activating' })];
}

if (sm.state === 'ACTIVE' && isMfrr) {
    if (signedWatts !== sm.last_signed_watts) {
        sm.last_signed_watts = signedWatts; flow.set('qw_sm', sm); setMfrr(true, qw_mode, signedWatts);
        setStatus('ACTIVE ' + signedWatts + ' W (updated)', 'yellow');
        return [null, execSp(signedWatts), publishState({ phase: 'setpoint_updated' })];
    }
    setStatus('ACTIVE ' + sm.last_signed_watts + ' W (hold)', 'yellow');
    return [null, null, null];
}

if (sm.state === 'ACTIVE' && !isMfrr) {
    sm = { state: 'IDLE', event_start_ts: null, last_signed_watts: 0, mqtt_lost_at: null, pending_token: null };
    flow.set('qw_sm', sm); setMfrr(false);
    setStatus('IDLE (released)', 'green');
    return [execDess('on'), execSp(0), publishState({ phase: 'released' })];
}

setStatus('IDLE', 'green');
return [null, null, null];

