node.status({ fill: 'blue', shape: 'dot', text: 'TEST ' + msg.payload });
function pubState(phase, extra) {
    node.send([null, null, { topic: TOPIC + '/state', retain: true, payload: Object.assign({ state: 'TEST', test_id: msg.payload, test_watts: cfg.watts, phase: phase, timestamp: new Date().toISOString() }, extra || {}) }]);
}
node.send([{ payload: 'off' }, null, null]); pubState('dess_off');
setTimeout(function () { node.send([null, { payload: String(cfg.watts) }, null]); pubState('setpoint', { setpoint_w: cfg.watts }); }, 2000);
setTimeout(function () { node.send([null, { payload: '0' }, null]); pubState('release'); }, 2000 + cfg.duration_s * 1000);
